/**
 * Subscription Repository
 *
 * Data access layer for Subscription, Plan, and Invoice entities.
 * Handles database operations for subscription management.
 *
 * @module modules/_core/subscription/subscription.repository
 *
 * @example
 * ```typescript
 * import { SubscriptionRepository } from '@/modules/_core/subscription/subscription.repository';
 *
 * const repo = container.resolve('SubscriptionRepository');
 * const subscription = await repo.findByOrganizationId('org_123');
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { PrismaClient, SubscriptionStatus, InvoiceStatus, Prisma } from '@prisma/client';

import { TOKENS } from '@/core/kernel/container';
import { AppException } from '@/core/exceptions/app.exception';

import type {
  Plan,
  Subscription,
  SubscriptionWithRelations,
  Invoice,
  SubscriptionListParams,
  InvoiceListParams,
  SubscriptionSummary,
  PlanSummary,
} from '@/modules/_core/subscription/subscription.types';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * Paginated result type
 */
export interface PaginatedResult<T> {
  /** Array of entities */
  data: T[];
  /** Pagination metadata */
  meta: {
    page: number;
    perPage: number;
    total: number;
    totalPages: number;
  };
}

/**
 * Create subscription data (input for repository)
 */
export interface CreateSubscriptionData {
  organizationId: string;
  planId: string;
  status?: SubscriptionStatus;
  currentPeriodStart: Date;
  currentPeriodEnd: Date;
  trialStart?: Date | null;
  trialEnd?: Date | null;
  paymentMethod?: string | null;
  metadata?: Prisma.JsonValue;
}

/**
 * Update subscription data (input for repository)
 */
export interface UpdateSubscriptionData {
  planId?: string;
  status?: SubscriptionStatus;
  currentPeriodStart?: Date;
  currentPeriodEnd?: Date;
  cancelAtPeriodEnd?: boolean;
  cancelledAt?: Date | null;
  trialEnd?: Date | null;
  paymentMethod?: string | null;
  lastPaymentAt?: Date | null;
  nextPaymentAt?: Date | null;
  metadata?: Prisma.JsonValue;
}

/**
 * Create invoice data (input for repository)
 */
export interface CreateInvoiceData {
  subscriptionId: string;
  invoiceNumber: string;
  status?: InvoiceStatus;
  subtotal: number;
  taxAmount: number;
  totalAmount: number;
  currency?: string;
  dueDate: Date;
  description?: string | null;
  lineItems?: Prisma.JsonValue;
  metadata?: Prisma.JsonValue;
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

const DEFAULT_PER_PAGE = 20;
const MAX_PER_PAGE = 100;

// -----------------------------------------------------------------------------
// Subscription Repository
// -----------------------------------------------------------------------------

/**
 * Repository for Subscription, Plan, and Invoice entity operations.
 *
 * Handles all database operations including:
 * - Plan CRUD
 * - Subscription CRUD and lifecycle
 * - Invoice management
 * - Feature and limit checks
 *
 * @example
 * ```typescript
 * @injectable()
 * class SubscriptionService {
 *   constructor(
 *     @inject('SubscriptionRepository') private repo: SubscriptionRepository
 *   ) {}
 *
 *   async getByOrg(orgId: string) {
 *     return this.repo.findByOrganizationId(orgId);
 *   }
 * }
 * ```
 */
@injectable()
export class SubscriptionRepository {
  constructor(
    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
  ) {}

  // ---------------------------------------------------------------------------
  // Plan Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all active plans
   *
   * @param includeInactive - Whether to include inactive plans
   * @returns Array of plans
   */
  async findAllPlans(includeInactive = false): Promise<Plan[]> {
    const where: Prisma.PlanWhereInput = includeInactive ? {} : { isActive: true };

    const plans = await this.prisma.plan.findMany({
      where,
      orderBy: { sortOrder: 'asc' },
    });

    return plans.map((plan) => this.toPlan(plan));
  }

  /**
   * Finds all plan summaries
   *
   * @param includeInactive - Whether to include inactive plans
   * @returns Array of plan summaries
   */
  async findAllPlanSummaries(includeInactive = false): Promise<PlanSummary[]> {
    const where: Prisma.PlanWhereInput = includeInactive ? {} : { isActive: true };

    const plans = await this.prisma.plan.findMany({
      where,
      select: {
        id: true,
        name: true,
        displayName: true,
        monthlyPrice: true,
        annualPrice: true,
        currency: true,
        sortOrder: true,
      },
      orderBy: { sortOrder: 'asc' },
    });

    return plans.map((plan) => ({
      id: plan.id,
      name: plan.name,
      displayName: plan.displayName,
      monthlyPrice: plan.monthlyPrice.toNumber(),
      annualPrice: plan.annualPrice.toNumber(),
      currency: plan.currency,
      sortOrder: plan.sortOrder,
    }));
  }

  /**
   * Finds a plan by ID
   *
   * @param id - Plan ID
   * @returns Plan or null
   */
  async findPlanById(id: string): Promise<Plan | null> {
    const plan = await this.prisma.plan.findUnique({
      where: { id },
    });

    return plan ? this.toPlan(plan) : null;
  }

  /**
   * Finds a plan by ID or throws
   *
   * @param id - Plan ID
   * @returns Plan
   * @throws {AppException} If not found
   */
  async findPlanByIdOrThrow(id: string): Promise<Plan> {
    const plan = await this.findPlanById(id);

    if (!plan) {
      throw AppException.notFound('Plan', id);
    }

    return plan;
  }

  /**
   * Finds a plan by name
   *
   * @param name - Plan name
   * @returns Plan or null
   */
  async findPlanByName(name: string): Promise<Plan | null> {
    const plan = await this.prisma.plan.findUnique({
      where: { name },
    });

    return plan ? this.toPlan(plan) : null;
  }

  /**
   * Gets the free plan
   *
   * @returns Free plan
   * @throws {AppException} If free plan not found
   */
  async getFreePlan(): Promise<Plan> {
    const plan = await this.findPlanByName('free');

    if (!plan) {
      throw AppException.serverError('Free plan not configured');
    }

    return plan;
  }

  // ---------------------------------------------------------------------------
  // Subscription Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all subscriptions with pagination and filtering
   *
   * @param params - Query parameters
   * @returns Paginated subscriptions
   */
  async findAllSubscriptions(
    params: SubscriptionListParams = {}
  ): Promise<PaginatedResult<SubscriptionSummary>> {
    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      status,
      planId,
      organizationId,
      expiringSoon,
      inTrial,
      search,
      sortBy = 'createdAt',
      sortOrder = 'desc',
    } = params;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where: Prisma.SubscriptionWhereInput = {
      ...(status && { status }),
      ...(planId && { planId }),
      ...(organizationId && { organizationId }),
      ...(expiringSoon && {
        currentPeriodEnd: {
          lte: new Date(Date.now() + expiringSoon * 24 * 60 * 60 * 1000),
          gte: new Date(),
        },
        status: 'ACTIVE',
      }),
      ...(inTrial !== undefined && {
        status: inTrial ? 'TRIALING' : { not: 'TRIALING' },
      }),
      ...(search && {
        organization: {
          OR: [
            { name: { contains: search, mode: 'insensitive' } },
            { email: { contains: search, mode: 'insensitive' } },
          ],
        },
      }),
    };

    // Build orderBy
    const orderBy: Prisma.SubscriptionOrderByWithRelationInput = {
      [sortBy]: sortOrder,
    };

    // Execute count and find in parallel
    const [total, subscriptions] = await Promise.all([
      this.prisma.subscription.count({ where }),
      this.prisma.subscription.findMany({
        where,
        include: {
          plan: { select: { name: true, displayName: true, monthlyPrice: true } },
          organization: { select: { name: true } },
        },
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    const data: SubscriptionSummary[] = subscriptions.map((sub) => ({
      id: sub.id,
      organizationId: sub.organizationId,
      organizationName: sub.organization.name,
      planName: sub.plan.displayName,
      status: sub.status,
      currentPeriodEnd: sub.currentPeriodEnd,
      monthlyPrice: sub.plan.monthlyPrice.toNumber(),
      createdAt: sub.createdAt,
    }));

    return {
      data,
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds a subscription by ID
   *
   * @param id - Subscription ID
   * @returns Subscription or null
   */
  async findSubscriptionById(id: string): Promise<Subscription | null> {
    const subscription = await this.prisma.subscription.findUnique({
      where: { id },
    });

    return subscription ? this.toSubscription(subscription) : null;
  }

  /**
   * Finds a subscription by ID with relations
   *
   * @param id - Subscription ID
   * @returns Subscription with relations or null
   */
  async findSubscriptionByIdWithRelations(id: string): Promise<SubscriptionWithRelations | null> {
    const subscription = await this.prisma.subscription.findUnique({
      where: { id },
      include: {
        plan: true,
        organization: {
          select: { id: true, name: true, slug: true },
        },
        invoices: {
          take: 5,
          orderBy: { createdAt: 'desc' },
        },
      },
    });

    if (!subscription) return null;

    return {
      ...this.toSubscription(subscription),
      plan: this.toPlan(subscription.plan),
      organization: subscription.organization,
      invoices: subscription.invoices.map((inv) => this.toInvoice(inv)),
    };
  }

  /**
   * Finds a subscription by ID or throws
   *
   * @param id - Subscription ID
   * @returns Subscription
   * @throws {AppException} If not found
   */
  async findSubscriptionByIdOrThrow(id: string): Promise<Subscription> {
    const subscription = await this.findSubscriptionById(id);

    if (!subscription) {
      throw AppException.notFound('Subscription', id);
    }

    return subscription;
  }

  /**
   * Finds a subscription by organization ID
   *
   * @param organizationId - Organization ID
   * @returns Subscription or null
   */
  async findByOrganizationId(organizationId: string): Promise<Subscription | null> {
    const subscription = await this.prisma.subscription.findUnique({
      where: { organizationId },
    });

    return subscription ? this.toSubscription(subscription) : null;
  }

  /**
   * Finds a subscription by organization ID with relations
   *
   * @param organizationId - Organization ID
   * @returns Subscription with relations or null
   */
  async findByOrganizationIdWithRelations(
    organizationId: string
  ): Promise<SubscriptionWithRelations | null> {
    const subscription = await this.prisma.subscription.findUnique({
      where: { organizationId },
      include: {
        plan: true,
        organization: {
          select: { id: true, name: true, slug: true },
        },
      },
    });

    if (!subscription) return null;

    return {
      ...this.toSubscription(subscription),
      plan: this.toPlan(subscription.plan),
      organization: subscription.organization,
    };
  }

  /**
   * Counts subscriptions by status
   *
   * @param status - Optional status filter
   * @returns Count
   */
  async countSubscriptions(status?: SubscriptionStatus): Promise<number> {
    return this.prisma.subscription.count({
      where: status ? { status } : {},
    });
  }

  // ---------------------------------------------------------------------------
  // Subscription Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new subscription
   *
   * @param data - Create data
   * @returns Created subscription
   */
  async createSubscription(data: CreateSubscriptionData): Promise<Subscription> {
    const subscription = await this.prisma.subscription.create({
      data: {
        organizationId: data.organizationId,
        planId: data.planId,
        status: data.status || SubscriptionStatus.TRIALING,
        currentPeriodStart: data.currentPeriodStart,
        currentPeriodEnd: data.currentPeriodEnd,
        trialStart: data.trialStart || null,
        trialEnd: data.trialEnd || null,
        paymentMethod: data.paymentMethod as never,
        metadata: data.metadata || {},
      },
    });

    return this.toSubscription(subscription);
  }

  /**
   * Updates a subscription
   *
   * @param id - Subscription ID
   * @param data - Update data
   * @returns Updated subscription
   */
  async updateSubscription(id: string, data: UpdateSubscriptionData): Promise<Subscription> {
    // Verify exists
    await this.findSubscriptionByIdOrThrow(id);

    const subscription = await this.prisma.subscription.update({
      where: { id },
      data: {
        ...(data.planId !== undefined && { planId: data.planId }),
        ...(data.status !== undefined && { status: data.status }),
        ...(data.currentPeriodStart !== undefined && { currentPeriodStart: data.currentPeriodStart }),
        ...(data.currentPeriodEnd !== undefined && { currentPeriodEnd: data.currentPeriodEnd }),
        ...(data.cancelAtPeriodEnd !== undefined && { cancelAtPeriodEnd: data.cancelAtPeriodEnd }),
        ...(data.cancelledAt !== undefined && { cancelledAt: data.cancelledAt }),
        ...(data.trialEnd !== undefined && { trialEnd: data.trialEnd }),
        ...(data.paymentMethod !== undefined && { paymentMethod: data.paymentMethod as never }),
        ...(data.lastPaymentAt !== undefined && { lastPaymentAt: data.lastPaymentAt }),
        ...(data.nextPaymentAt !== undefined && { nextPaymentAt: data.nextPaymentAt }),
        ...(data.metadata !== undefined && { metadata: data.metadata }),
      },
    });

    return this.toSubscription(subscription);
  }

  /**
   * Updates subscription status
   *
   * @param id - Subscription ID
   * @param status - New status
   * @returns Updated subscription
   */
  async updateSubscriptionStatus(id: string, status: SubscriptionStatus): Promise<Subscription> {
    await this.findSubscriptionByIdOrThrow(id);

    const subscription = await this.prisma.subscription.update({
      where: { id },
      data: { status },
    });

    return this.toSubscription(subscription);
  }

  // ---------------------------------------------------------------------------
  // Invoice Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all invoices with pagination and filtering
   *
   * @param params - Query parameters
   * @returns Paginated invoices
   */
  async findAllInvoices(params: InvoiceListParams = {}): Promise<PaginatedResult<Invoice>> {
    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      status,
      subscriptionId,
      organizationId,
      startDate,
      endDate,
      sortBy = 'createdAt',
      sortOrder = 'desc',
    } = params;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where: Prisma.InvoiceWhereInput = {
      ...(status && { status }),
      ...(subscriptionId && { subscriptionId }),
      ...(organizationId && { subscription: { organizationId } }),
      ...(startDate && { createdAt: { gte: startDate } }),
      ...(endDate && { createdAt: { lte: endDate } }),
    };

    // Build orderBy
    const orderBy: Prisma.InvoiceOrderByWithRelationInput = {
      [sortBy]: sortOrder,
    };

    // Execute count and find in parallel
    const [total, invoices] = await Promise.all([
      this.prisma.invoice.count({ where }),
      this.prisma.invoice.findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data: invoices.map((inv) => this.toInvoice(inv)),
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds an invoice by ID
   *
   * @param id - Invoice ID
   * @returns Invoice or null
   */
  async findInvoiceById(id: string): Promise<Invoice | null> {
    const invoice = await this.prisma.invoice.findUnique({
      where: { id },
    });

    return invoice ? this.toInvoice(invoice) : null;
  }

  /**
   * Finds invoices by subscription ID
   *
   * @param subscriptionId - Subscription ID
   * @returns Array of invoices
   */
  async findInvoicesBySubscriptionId(subscriptionId: string): Promise<Invoice[]> {
    const invoices = await this.prisma.invoice.findMany({
      where: { subscriptionId },
      orderBy: { createdAt: 'desc' },
    });

    return invoices.map((inv) => this.toInvoice(inv));
  }

  /**
   * Creates an invoice
   *
   * @param data - Create data
   * @returns Created invoice
   */
  async createInvoice(data: CreateInvoiceData): Promise<Invoice> {
    const invoice = await this.prisma.invoice.create({
      data: {
        subscriptionId: data.subscriptionId,
        invoiceNumber: data.invoiceNumber,
        status: data.status || InvoiceStatus.DRAFT,
        subtotal: data.subtotal,
        taxAmount: data.taxAmount,
        totalAmount: data.totalAmount,
        currency: data.currency || 'TRY',
        dueDate: data.dueDate,
        description: data.description || null,
        lineItems: data.lineItems || [],
        metadata: data.metadata || {},
      },
    });

    return this.toInvoice(invoice);
  }

  /**
   * Updates invoice status
   *
   * @param id - Invoice ID
   * @param status - New status
   * @param paidAt - Payment date (if paid)
   * @returns Updated invoice
   */
  async updateInvoiceStatus(
    id: string,
    status: InvoiceStatus,
    paidAt?: Date
  ): Promise<Invoice> {
    const invoice = await this.prisma.invoice.update({
      where: { id },
      data: {
        status,
        ...(paidAt && { paidAt }),
      },
    });

    return this.toInvoice(invoice);
  }

  // ---------------------------------------------------------------------------
  // Helper Methods
  // ---------------------------------------------------------------------------

  /**
   * Converts Prisma Plan to domain Plan
   */
  private toPlan(prisma: {
    id: string;
    name: string;
    displayName: string;
    description: string | null;
    monthlyPrice: Prisma.Decimal;
    annualPrice: Prisma.Decimal;
    currency: string;
    features: Prisma.JsonValue;
    limits: Prisma.JsonValue;
    isActive: boolean;
    sortOrder: number;
    createdAt: Date;
    updatedAt: Date;
  }): Plan {
    return {
      id: prisma.id,
      name: prisma.name,
      displayName: prisma.displayName,
      description: prisma.description,
      monthlyPrice: prisma.monthlyPrice.toNumber(),
      annualPrice: prisma.annualPrice.toNumber(),
      currency: prisma.currency,
      features: prisma.features as Plan['features'],
      limits: prisma.limits as Plan['limits'],
      isActive: prisma.isActive,
      sortOrder: prisma.sortOrder,
      createdAt: prisma.createdAt,
      updatedAt: prisma.updatedAt,
    };
  }

  /**
   * Converts Prisma Subscription to domain Subscription
   */
  private toSubscription(prisma: {
    id: string;
    organizationId: string;
    planId: string;
    status: SubscriptionStatus;
    currentPeriodStart: Date;
    currentPeriodEnd: Date;
    cancelAtPeriodEnd: boolean;
    cancelledAt: Date | null;
    trialStart: Date | null;
    trialEnd: Date | null;
    paymentMethod: string | null;
    lastPaymentAt: Date | null;
    nextPaymentAt: Date | null;
    metadata: Prisma.JsonValue;
    createdAt: Date;
    updatedAt: Date;
  }): Subscription {
    return {
      id: prisma.id,
      organizationId: prisma.organizationId,
      planId: prisma.planId,
      status: prisma.status,
      currentPeriodStart: prisma.currentPeriodStart,
      currentPeriodEnd: prisma.currentPeriodEnd,
      cancelAtPeriodEnd: prisma.cancelAtPeriodEnd,
      cancelledAt: prisma.cancelledAt,
      trialStart: prisma.trialStart,
      trialEnd: prisma.trialEnd,
      paymentMethod: prisma.paymentMethod as Subscription['paymentMethod'],
      lastPaymentAt: prisma.lastPaymentAt,
      nextPaymentAt: prisma.nextPaymentAt,
      metadata: prisma.metadata as Subscription['metadata'],
      createdAt: prisma.createdAt,
      updatedAt: prisma.updatedAt,
    };
  }

  /**
   * Converts Prisma Invoice to domain Invoice
   */
  private toInvoice(prisma: {
    id: string;
    subscriptionId: string;
    invoiceNumber: string;
    status: InvoiceStatus;
    subtotal: Prisma.Decimal;
    taxAmount: Prisma.Decimal;
    totalAmount: Prisma.Decimal;
    currency: string;
    dueDate: Date;
    paidAt: Date | null;
    paymentMethod: string | null;
    description: string | null;
    lineItems: Prisma.JsonValue;
    metadata: Prisma.JsonValue;
    createdAt: Date;
    updatedAt: Date;
  }): Invoice {
    return {
      id: prisma.id,
      subscriptionId: prisma.subscriptionId,
      invoiceNumber: prisma.invoiceNumber,
      status: prisma.status,
      subtotal: prisma.subtotal.toNumber(),
      taxAmount: prisma.taxAmount.toNumber(),
      totalAmount: prisma.totalAmount.toNumber(),
      currency: prisma.currency,
      dueDate: prisma.dueDate,
      paidAt: prisma.paidAt,
      paymentMethod: prisma.paymentMethod as Invoice['paymentMethod'],
      description: prisma.description,
      lineItems: prisma.lineItems as Invoice['lineItems'],
      metadata: prisma.metadata as Invoice['metadata'],
      createdAt: prisma.createdAt,
      updatedAt: prisma.updatedAt,
    };
  }
}
